    code: `'use client';
import { useEffect, useRef } from 'react';

interface Blob { x:number; y:number; vx:number; vy:number; r:number; life:number; h:number; burst:boolean; }

const noise = (x:number, y:number, t:number) =>
  Math.sin(x*.008+t*.5)*Math.cos(y*.006-t*.3)*Math.sin((x+y)*.004+t*.2);

export const LiquidCursorTrail = () => {
  const canvasRef = useRef<HTMLCanvasElement>(null);

  useEffect(() => {
    const c = canvasRef.current!;
    const ctx = c.getContext('2d')!;
    let W = c.width = window.innerWidth, H = c.height = window.innerHeight;
    let mx = W/2, my = H/2, pmx = mx, pmy = my, vx = 0, vy = 0, t = 0;
    const blobs: Blob[] = [];
    let raf: number;

    const onMove = (e: MouseEvent) => {
      pmx = mx; pmy = my; mx = e.clientX; my = e.clientY;
      vx = mx - pmx; vy = my - pmy;
    };
    const onClick = () => {
      for (let i = 0; i < 12; i++) {
        const a = i/12*Math.PI*2, sp = 3+Math.random()*5;
        blobs.push({x:mx,y:my,vx:Math.cos(a)*sp,vy:Math.sin(a)*sp,r:60+Math.random()*40,life:1,h:160+Math.random()*80,burst:true});
      }
    };
    const onResize = () => { W = c.width = window.innerWidth; H = c.height = window.innerHeight; };

    window.addEventListener('mousemove', onMove);
    window.addEventListener('mousedown', onClick);
    window.addEventListener('resize', onResize);

    const draw = () => {
      raf = requestAnimationFrame(draw);
      t += 0.02;
      ctx.fillStyle = 'rgba(5,5,16,.18)'; ctx.fillRect(0,0,W,H);
      const spd = Math.sqrt(vx*vx+vy*vy);
      if (spd > 0.5) blobs.push({x:mx,y:my,vx:vx*.1,vy:vy*.1,r:20+spd*2,life:1,h:160+spd*3,burst:false});
      vx *= .85; vy *= .85;

      for (let i = blobs.length-1; i >= 0; i--) {
        const b = blobs[i];
        b.x += b.vx; b.y += b.vy; b.vx *= .92; b.vy *= .92;
        b.life -= b.burst ? 0.018 : 0.012;
        if (b.life <= 0) { blobs.splice(i,1); continue; }
        const nr = b.r*(1+noise(b.x,b.y,t)*0.4);
        const g = ctx.createRadialGradient(b.x,b.y,0,b.x,b.y,nr);
        g.addColorStop(0,'hsla('+b.h+',90%,65%,'+(b.life*.6)+')');
        g.addColorStop(.5,'hsla('+b.h+',70%,45%,'+(b.life*.25)+')');
        g.addColorStop(1,'hsla('+b.h+',50%,30%,0)');
        ctx.save();
        const nx = noise(b.x+100,b.y,t)*.15, ny = noise(b.x,b.y+100,t)*.15;
        ctx.transform(1+nx,ny,nx,1+ny,b.x*(-nx),b.y*(-ny));
        ctx.beginPath(); ctx.arc(b.x,b.y,nr,0,Math.PI*2);
        ctx.fillStyle = g; ctx.fill(); ctx.restore();
      }
    };
    draw();
    return () => {
      cancelAnimationFrame(raf);
      window.removeEventListener('mousemove', onMove);
      window.removeEventListener('mousedown', onClick);
      window.removeEventListener('resize', onResize);
    };
  }, []);

  return (
    <div className="relative w-full h-screen overflow-hidden" style={{background:'#050510'}}>
      <canvas ref={canvasRef} className="block w-full h-full" />
      <p className="absolute bottom-7 left-1/2 -translate-x-1/2 text-white/20 text-[9px] font-bold tracking-[.4em] uppercase pointer-events-none">
        Move mouse &bull; Click to burst
      </p>
    </div>
  );
};`,
    prompt: "Create a canvas background where moving the cursor spawns organic liquid shadow blobs. Each blob is a radial gradient (emeraldÃƒÆ’Ã†â€™Ãƒâ€šÃ‚Â¢ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â‚¬Å¡Ã‚Â¬Ãƒâ€šÃ‚Â ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â‚¬Å¡Ã‚Â¬ÃƒÂ¢Ã¢â‚¬Å¾Ã‚Â¢cyan, hsla) that fades over ~80 frames. Use a sine/cosine noise function to distort the blob radius (ÃƒÆ’Ã†â€™ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¡ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â±40%) and apply a canvas transform matrix distortion using noise values to make each blob appear to morph. On mousedown, burst 12 blobs in all directions. Blob velocity inherits cursor speed. Background #050510 with 18% opacity fill per frame for motion trails.",
