    code: `'use client';
import { useEffect, useRef } from 'react';

interface Ripple { x:number; y:number; radius:number; life:number; speed:number; }
interface Point { x:number; y:number; z:number; baseX:number; baseY:number; }

export const QuantumTerrain = () => {
  const canvasRef = useRef<HTMLCanvasElement>(null);

  useEffect(() => {
    const c = canvasRef.current!;
    const ctx = c.getContext('2d')!;
    let W = c.width = window.innerWidth, H = c.height = window.innerHeight;
    const cols = 55, rows = 40;
    let spacingX = W / (cols - 1), spacingY = H / (rows - 1);
    const points: Point[][] = [];
    const ripples: Ripple[] = [];
    let raf: number;

    for (let y = 0; y < rows; y++) {
      const row = [];
      for (let x = 0; x < cols; x++) {
        row.push({ x: x*spacingX, y: y*spacingY, z: 0, baseX: x*spacingX, baseY: y*spacingY });
      }
      points.push(row);
    }

    const onMove = (e: MouseEvent) => {
      // Throttle ripple creation slightly
      if (Math.random() > 0.3) {
        ripples.push({ x: e.clientX, y: e.clientY, radius: 0, life: 1, speed: 4 + Math.random() * 4 });
      }
    };
    
    const onResize = () => {
      W = c.width = window.innerWidth; H = c.height = window.innerHeight;
      spacingX = W / (cols - 1); spacingY = H / (rows - 1);
      for (let y = 0; y < rows; y++) {
        for (let x = 0; x < cols; x++) {
          points[y][x].baseX = x * spacingX; points[y][x].baseY = y * spacingY;
        }
      }
    };

    window.addEventListener('mousemove', onMove);
    window.addEventListener('resize', onResize);

    const draw = () => {
      raf = requestAnimationFrame(draw);
      ctx.fillStyle = 'rgba(2,2,5,0.4)'; ctx.fillRect(0, 0, W, H);
      
      for (let i = ripples.length - 1; i >= 0; i--) {
        const r = ripples[i];
        r.radius += r.speed; r.life -= 0.012;
        if (r.life <= 0) ripples.splice(i, 1);
      }
      
      for (let y = 0; y < rows; y++) {
        for (let x = 0; x < cols; x++) {
          const p = points[y][x];
          p.z = 0;
          for (let i = 0; i < ripples.length; i++) {
            const r = ripples[i];
            const dx = p.baseX - r.x, dy = p.baseY - r.y, dist = Math.sqrt(dx*dx+dy*dy);
            const distToRing = Math.abs(dist - r.radius);
            if (distToRing < 120) {
              const force = (120 - distToRing) / 120;
              p.z += Math.sin(distToRing * 0.08 - r.life * 12) * force * 35 * r.life;
            }
          }
          p.x = p.baseX; p.y = p.baseY - p.z;
        }
      }
      
      ctx.lineWidth = 1.5;
      // Draw horizontal and vertical lines
      for (let y = 0; y < rows - 1; y++) {
        for (let x = 0; x < cols - 1; x++) {
          const p = points[y][x], pRight = points[y][x+1], pDown = points[y+1][x];
          const depth = Math.max(0, Math.min(1, (p.z + 35) / 70));
          ctx.strokeStyle = 'hsla(' + (180 + depth*70) + ', 100%, ' + (20 + depth*60) + '%, ' + (0.05 + depth*0.95) + ')';
          
          ctx.beginPath(); ctx.moveTo(p.x, p.y); ctx.lineTo(pRight.x, pRight.y); ctx.stroke();
          ctx.beginPath(); ctx.moveTo(p.x, p.y); ctx.lineTo(pDown.x, pDown.y); ctx.stroke();
        }
      }
    };
    draw();
    
    return () => {
      cancelAnimationFrame(raf);
      window.removeEventListener('mousemove', onMove);
      window.removeEventListener('resize', onResize);
    };
  }, []);

  return (
    <div className="relative w-full h-screen bg-[#020205] overflow-hidden">
      <canvas ref={canvasRef} className="block w-full h-full" />
      <div className="absolute bottom-8 left-1/2 -translate-x-1/2 text-[#00ffaa]/50 text-[9px] font-bold tracking-[0.4em] uppercase pointer-events-none">
        Move mouse to generate ripples
      </div>
    </div>
  );
};`,
    prompt: "Create a 3D wireframe terrain effect using pure 2D Canvas. Define a grid of points (55 cols, 40 rows). Moving the mouse drops 'ripples' (expanding rings). Points calculate their distance to all active ripples, and their Z-height is modified using a sine wave based on distance to the ring and the ripple's life. The Canvas draws horizontal and vertical lines connecting the points. The lines are colored cyan to bright emerald based on the Z-height of the starting point, with higher opacity for peaks. Background is a deep space blue (#020205) with 40% alpha fill per frame for motion trails.",
