    code: `'use client';
import { useRef, useMemo, useState } from 'react';
import { Canvas, useFrame } from '@react-three/fiber';
import * as THREE from 'three';

const ParticleCore = () => {
  const pointsRef = useRef<THREE.Points>(null);
  const [hovered, setHovered] = useState(false);
  const target = useRef(new THREE.Vector3());
  
  const { positions, colors, basePositions, numParticles } = useMemo(() => {
    const amountX = 80;
    const amountY = 80;
    const spacing = 6;
    const num = amountX * amountY;
    const pos = new Float32Array(num * 3);
    const col = new Float32Array(num * 3);
    const base = new Float32Array(num * 3);
    const color = new THREE.Color();
    
    let idx = 0;
    for (let ix = 0; ix < amountX; ix++) {
      for (let iy = 0; iy < amountY; iy++) {
        const theta = (ix / amountX) * Math.PI * 4;
        const y = (iy - amountY / 2) * spacing;
        const radius = 120 + Math.sin((iy / amountY) * Math.PI) * 40;
        
        const x = Math.cos(theta) * radius;
        const z = Math.sin(theta) * radius;
        
        pos[idx] = x; pos[idx+1] = y; pos[idx+2] = z;
        base[idx] = x; base[idx+1] = y; base[idx+2] = z;
        
        color.setHSL((ix / amountX) * 0.2 + 0.4, 0.9, 0.6);
        col[idx] = color.r; col[idx+1] = color.g; col[idx+2] = color.b;
        
        idx += 3;
      }
    }
    return { positions: pos, colors: col, basePositions: base, numParticles: num };
  }, []);

  useFrame((state) => {
    if (!pointsRef.current) return;
    const t = state.clock.getElapsedTime();
    const pts = pointsRef.current;
    
    pts.rotation.y = t * 0.2;
    pts.rotation.z = Math.sin(t * 0.1) * 0.1;
    
    // Unproject mouse to a 3D coordinate on z=0 plane
    target.current.set(state.mouse.x, state.mouse.y, 0.5).unproject(state.camera);
    const dir = target.current.clone().sub(state.camera.position).normalize();
    const dist = -state.camera.position.z / dir.z;
    target.current.copy(state.camera.position).add(dir.multiplyScalar(dist));
    
    const invMatrix = new THREE.Matrix4().copy(pts.matrixWorld).invert();
    const localTarget = target.current.clone().applyMatrix4(invMatrix);
    
    const posArray = pts.geometry.attributes.position.array as Float32Array;
    
    for (let i = 0; i < numParticles; i++) {
      const i3 = i * 3;
      const bx = basePositions[i3], by = basePositions[i3+1], bz = basePositions[i3+2];
      
      const wave = Math.sin(bx * 0.02 + t * 2) * 10 + Math.cos(by * 0.02 + t * 1.5) * 10;
      
      const dx = bx - localTarget.x, dy = by - localTarget.y, dz = bz - localTarget.z;
      const distSq = dx*dx + dy*dy + dz*dz;
      let force = 0;
      if (hovered && distSq < 25000) {
        force = (25000 - distSq) / 25000 * 40;
      }
      
      const len = Math.sqrt(distSq) || 1;
      const nx = dx/len, ny = dy/len, nz = dz/len;
      
      posArray[i3] = bx + nx * force + Math.cos(t + by * 0.05) * wave;
      posArray[i3+1] = by + ny * force;
      posArray[i3+2] = bz + nz * force + Math.sin(t + bx * 0.05) * wave;
    }
    
    pts.geometry.attributes.position.needsUpdate = true;
  });

  return (
    <points 
      ref={pointsRef} 
      onPointerOver={() => setHovered(true)} 
      onPointerOut={() => setHovered(false)}
    >
      <bufferGeometry>
        <bufferAttribute attach="attributes-position" count={numParticles} array={positions} itemSize={3} />
        <bufferAttribute attach="attributes-color" count={numParticles} array={colors} itemSize={3} />
      </bufferGeometry>
      <pointsMaterial size={2} vertexColors transparent opacity={0.8} blending={THREE.AdditiveBlending} depthWrite={false} />
    </points>
  );
};

export const AbyssalMatrixCore = () => {
  return (
    <div className="relative w-full h-screen bg-[#010103] overflow-hidden font-sans">
      <Canvas camera={{ position: [0, 0, 450], fov: 45 }}>
        <fog attach="fog" args={['#010103', 200, 1000]} />
        <ParticleCore />
      </Canvas>
      <div className="absolute bottom-8 left-1/2 -translate-x-1/2 text-white/40 text-[9px] font-bold tracking-[0.4em] uppercase pointer-events-none z-30">
        Hover to repel the core
      </div>
    </div>
  );
};`,
